#include "curl.h"

#include "memdebug.h" /* LAST include file */

static CURLcode unit_setup(void)
{
  CURLcode res = CURLE_OK;
  global_init(CURL_GLOBAL_ALL);
  return res;
}

static void unit_stop(void)
{
  curl_global_cleanup();
}

UNITTEST_START
{
  CURL *curl = curl_easy_init();
  fail_if(!curl, "curl_easy_init() failed");

  /* Test 1: Set H3_STREAM_PRIORITY with urgency=5 */
  CURLcode res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=5");
  fail_if(res != CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY) failed");

  /* Test 2: Set H3_STREAM_PRIORITY with urgency=2 and incremental flag */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=2,i");
  fail_if(res != CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY) failed with incremental");

  /* Test 3: Set with urgency=7 (maximum) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=7");
  fail_if(res != CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY) failed for max urgency");

  /* Test 4: Set with urgency=0 (minimum) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, "u=0");
  fail_if(res != CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY) failed for min urgency");

  /* Test 5: Set with NULL (should handle gracefully) */
  res = curl_easy_setopt(curl, CURLOPT_H3_STREAM_PRIORITY, NULL);
  fail_if(res != CURLE_OK, "curl_easy_setopt(CURLOPT_H3_STREAM_PRIORITY) failed for NULL");

  curl_easy_cleanup(curl);
}
UNITTEST_STOP

